transform_js:
var maxV = 0;
rawData.rows.forEach(function(r) { if (r.v > maxV) maxV = r.v; });
var totalDays = rawData.rows.length;
transformedData = rawData.rows.map(function(r, i) {
  // 1 year = 1 rotation (using approx 365.25 days per year for leap year handling)
  var angleDegrees = (i / 365.25) * 360;
  // Radius starts at 10 (inside) and goes to 100 (outside edge)
  var radius = 10 + (i / totalDays) * 90;
  return { 
    value: [radius, angleDegrees, r.v, r.t],
    // Points are bigger if value is larger
    symbolSize: Math.max(2, (r.v / maxV) * 12)
  };
});

echarts_js:
var months = ['1月', '2月', '3月', '4月', '5月', '6月', '7月', '8月', '9月', '10月', '11月', '12月'];

option = {
  title: { text: '10-Year Spiral Plot', left: 'center', top: 10, textStyle: { color: '#333' } },
  tooltip: { 
    formatter: function(p) { 
      return p.data.value[3] + '<br/>Value: ' + p.data.value[2].toFixed(1); 
    } 
  },
  // Reduce polar radius so labels fit inside the canvas
  polar: { center: ['50%', '55%'], radius: '70%' },
  angleAxis: { 
    type: 'value', 
    min: 0, 
    max: 360, 
    interval: 30, // 30 degrees per month
    startAngle: 90, // Start at the top (12 o'clock)
    splitLine: { show: true, lineStyle: { color: '#e0e0e0', type: 'dashed' } },
    axisLabel: { 
      show: true,
      margin: 15,
      formatter: function(value) {
        if (value === 360) return ''; // don't duplicate 0 and 360
        return months[Math.round(value / 30)] || '';
      },
      color: '#333',
      fontSize: 12,
      fontWeight: 'bold'
    },
    axisTick: { show: true, lineStyle: { color: '#ccc' } },
    axisLine: { show: true, lineStyle: { color: '#ccc' } }
  },
  radiusAxis: { 
    min: 0, 
    max: 100, 
    splitNumber: 5, 
    splitLine: { show: true, lineStyle: { color: '#eee', type: 'solid' } },
    axisLabel: { 
      show: true, 
      color: '#666', 
      fontSize: 10,
      margin: 2,
      formatter: function(value) {
        if (value <= 10) return '';
        var year = 2016 + Math.round((value - 10) / 9);
        return year + '年';
      }
    },
    axisLine: { show: false },
    axisTick: { show: false },
    z: 10 // bring labels to front
  },
  visualMap: { 
    min: 0, 
    max: 100, 
    dimension: 2, 
    calculable: true, 
    inRange: { color: ['#d4e4fc', '#4071fa', '#1a3cab'] }, 
    right: 10, 
    top: 'center' 
  },
  series: [{
    type: 'scatter',
    coordinateSystem: 'polar',
    data: transformedData,
    itemStyle: { opacity: 0.9, borderColor: '#fff', borderWidth: 0.2 }
  }, {
    type: 'line',
    coordinateSystem: 'polar',
    data: transformedData,
    lineStyle: { color: '#ccc', width: 1, opacity: 0.4 },
    symbol: 'none',
    zlevel: -1
  }]
};
